"use client";

import { motion } from "framer-motion";
import { useEffect, useState } from "react";
import { cn } from "@/lib/utils";
import { useMetricsStore } from "@/lib/stores/metrics-store";

const stages = [
  { id: "cpu", label: "CPU", detail: "JavaScript prepares the frame, updates uniforms, and schedules commands." },
  { id: "js", label: "JavaScript", detail: "Application logic builds render bundles and vertex data." },
  { id: "encoder", label: "Command Encoder", detail: "Records GPU commands into a command buffer." },
  { id: "buffer", label: "Command Buffer", detail: "Serialized GPU work ready for submission." },
  { id: "queue", label: "GPU Queue", detail: "The queue serially executes command buffers." },
  { id: "vertex", label: "Vertex Shader", detail: "Processes each vertex and outputs clip-space positions." },
  { id: "assembly", label: "Primitive Assembly", detail: "Vertices are grouped into triangles." },
  { id: "rasterizer", label: "Rasterizer", detail: "Triangles are converted into fragments." },
  { id: "fragment", label: "Fragment Shader", detail: "Determines the color of each fragment." },
  { id: "depth", label: "Depth Buffer", detail: "Z-testing discards hidden fragments." },
  { id: "framebuffer", label: "Framebuffer", detail: "Final color pixels are written." },
  { id: "present", label: "Presentation", detail: "The swap chain displays the image on screen." }
];

const pipelineStageCycle = [
  "cpu",
  "js",
  "encoder",
  "buffer",
  "queue",
  "vertex",
  "assembly",
  "rasterizer",
  "fragment",
  "depth",
  "framebuffer",
  "present"
];

export function PipelineVisualizerPanel() {
  const [activeStage, setActiveStage] = useState<string | null>(null);
  const [pulseStage, setPulseStage] = useState<string | null>(null);
  const framePulse = useMetricsStore((s) => s.metrics.framePulse);

  useEffect(() => {
    let step = 0;
    const interval = setInterval(() => {
      setPulseStage(pipelineStageCycle[step]!);
      step = (step + 1) % pipelineStageCycle.length;
    }, 120);
    return () => clearInterval(interval);
  }, [framePulse]);

  return (
    <div className="flex h-full flex-col overflow-hidden rounded-2xl border border-white/10 bg-[#0B0C15]/80 p-6 shadow-card">
      <div className="mb-4">
        <span className="text-[10px] uppercase tracking-[0.3em] text-brand-subtle">GPU Pipeline</span>
        <h2 className="mt-1 font-display text-lg font-semibold text-white">Graphics Pipeline Visualizer</h2>
        <p className="text-xs text-slate-400">Hover a stage to see what it does. The pulsing stage follows the live render loop.</p>
      </div>

      <div className="flex flex-1 flex-col items-center gap-2 overflow-y-auto py-2">
        {stages.map((stage, i) => (
          <StageNode
            key={stage.id}
            stage={stage}
            index={i}
            isActive={activeStage === stage.id}
            isPulsing={pulseStage === stage.id}
            onHover={() => setActiveStage(stage.id)}
            onLeave={() => setActiveStage(null)}
          />
        ))}
      </div>
    </div>
  );
}

function StageNode({
  stage,
  index,
  isActive,
  isPulsing,
  onHover,
  onLeave
}: {
  stage: (typeof stages)[number];
  index: number;
  isActive: boolean;
  isPulsing: boolean;
  onHover: () => void;
  onLeave: () => void;
}) {
  return (
    <motion.div
      initial={{ opacity: 0, x: -20 }}
      animate={{ opacity: 1, x: 0 }}
      transition={{ delay: index * 0.05 }}
      onMouseEnter={onHover}
      onMouseLeave={onLeave}
      className={cn(
        "group relative w-full max-w-md cursor-default rounded-xl border px-4 py-3 text-center transition-all",
        isActive || isPulsing
          ? "border-brand/50 bg-brand/15 text-white shadow-[0_0_30px_rgba(108,140,255,0.2)]"
          : "border-white/10 bg-white/5 text-slate-300 hover:border-white/20 hover:bg-white/10"
      )}
    >
      <div className="flex items-center justify-center gap-2">
        <span className="text-[10px] font-mono text-brand-subtle">{String(index + 1).padStart(2, "0")}</span>
        <span className="text-xs font-semibold">{stage.label}</span>
      </div>
      <motion.div
        initial={{ height: 0, opacity: 0 }}
        animate={{ height: isActive ? "auto" : 0, opacity: isActive ? 1 : 0 }}
        className="overflow-hidden"
      >
        <p className="mt-2 text-[11px] leading-relaxed text-slate-300">{stage.detail}</p>
      </motion.div>
      {index < 11 ? (
        <div className="absolute left-1/2 top-full z-10 -translate-x-1/2">
          <motion.div
            animate={{ y: [0, 6, 0], opacity: [0.4, 1, 0.4] }}
            transition={{ duration: 1.5, repeat: Infinity, delay: index * 0.1 }}
            className="text-brand-subtle"
          >
            <span className="block text-[10px]">↓</span>
          </motion.div>
        </div>
      ) : null}
      {isPulsing ? (
        <motion.div
          layoutId="pipeline-pulse"
          className="absolute inset-0 rounded-xl border-2 border-brand/40"
          initial={{ opacity: 0 }}
          animate={{ opacity: [0, 1, 0] }}
          transition={{ duration: 0.8, repeat: Infinity }}
        />
      ) : null}
    </motion.div>
  );
}
